const fs = require('fs');
const path = require('path');

const { place_id, slug, build_dir } = $input.first().json.body;

const vercelToken = process.env.VERCEL_TOKEN || $env.VERCEL_TOKEN;
const vercelTeam = process.env.VERCEL_TEAM_ID || $env.VERCEL_TEAM_ID || '';

if (!vercelToken) {
  return [{ json: { error: 'VERCEL_TOKEN not configured' } }];
}

if (!build_dir || !slug) {
  return [{ json: { error: 'Missing required fields: slug, build_dir' } }];
}

const projectName = `duocode-${slug}`;
const baseUrl = 'https://api.vercel.com';
const headers = {
  'Authorization': `Bearer ${vercelToken}`,
  'Content-Type': 'application/json'
};

// Step 1: Create or get project
let projectId;
try {
  const createResp = await this.helpers.httpRequest({
    method: 'POST',
    url: `${baseUrl}/v10/projects${vercelTeam ? '?teamId=' + vercelTeam : ''}`,
    headers,
    body: {
      name: projectName,
      framework: null,
      buildCommand: '',
      outputDirectory: ''
    }
  });
  projectId = createResp.id;
} catch (err) {
  // Project may already exist, try to get it
  try {
    const getResp = await this.helpers.httpRequest({
      method: 'GET',
      url: `${baseUrl}/v9/projects/${projectName}${vercelTeam ? '?teamId=' + vercelTeam : ''}`,
      headers
    });
    projectId = getResp.id;
  } catch (e) {
    return [{ json: { error: 'Failed to create/get project: ' + e.message } }];
  }
}

// Step 2: Collect files from build_dir
function collectFiles(dir, base = '') {
  const results = [];
  try {
    const entries = fs.readdirSync(dir, { withFileTypes: true });
    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);
      const relPath = base ? `${base}/${entry.name}` : entry.name;
      if (entry.isDirectory()) {
        results.push(...collectFiles(fullPath, relPath));
      } else {
        const content = fs.readFileSync(fullPath);
        results.push({
          file: relPath,
          data: content.toString('base64'),
          encoding: 'base64'
        });
      }
    }
  } catch (e) {
    // directory may not exist
  }
  return results;
}

const files = collectFiles(build_dir);

if (files.length === 0) {
  return [{ json: { error: 'No files found in build_dir: ' + build_dir } }];
}

// Step 3: Create deployment
try {
  const deployResp = await this.helpers.httpRequest({
    method: 'POST',
    url: `${baseUrl}/v13/deployments${vercelTeam ? '?teamId=' + vercelTeam : ''}`,
    headers,
    body: {
      name: projectName,
      files,
      target: 'production',
      projectSettings: {
        framework: null
      }
    }
  });

  return [{
    json: {
      status: 'deployed',
      place_id,
      slug,
      project_name: projectName,
      project_id: projectId,
      deployment_id: deployResp.id,
      url: `https://${deployResp.url}`,
      ready_state: deployResp.readyState || 'QUEUED',
      created_at: new Date().toISOString()
    }
  }];
} catch (err) {
  return [{ json: { error: 'Deployment failed: ' + err.message, place_id, slug } }];
}

